mapper.select:
select * from ( select origin.*, count(*) over() as total_count, row_number() over(order by origin.play_count desc, origin.win_count desc, origin.partner_name asc) as rn from ( select p2.ck_streamer as partner_no, s.streamer_name as partner_name, s.streamer_soop_id as partner_soop_id, count(*) as play_count, sum(case when c.ck_winner = p1.ck_side then 1 else 0 end) as win_count, sum(case when c.ck_winner != p1.ck_side then 1 else 0 end) as lose_count from ck_participant p1 join ck_participant p2 on p1.ck_id = p2.ck_id and p1.ck_side = p2.ck_side and p1.ck_streamer != p2.ck_streamer join ck c on p1.ck_id = c.ck_id join streamer s on p2.ck_streamer = s.streamer_no where p1.ck_streamer = #{keyword}
and lower(s.streamer_name) like '%' || lower(#{searchKeyword}) || '%'
group by p2.ck_streamer, s.streamer_name, s.streamer_soop_id ) origin ) where rn between #{begin} and #{end} order by rn
